"""
Stock universe definitions for NSE India.

Start with Nifty 50 — the structure is designed to expand to Nifty 500 easily.
To expand: populate NIFTY500_STOCKS with the same dict format and switch
the UNIVERSE variable in app.py to "NIFTY500".
"""

def _get_custom_stocks_from_db() -> list[dict]:
    """Read universe='CUSTOM' stocks from SQLite. Returns [] if DB unavailable."""
    try:
        from .db import get_connection
        conn = get_connection()
        try:
            cur = conn.cursor()
            cur.execute(
                "SELECT symbol, name, sector FROM stocks WHERE universe = 'CUSTOM' ORDER BY name"
            )
            return [
                {"symbol": r[0], "name": r[1], "sector": r[2] or "Custom"}
                for r in cur.fetchall()
            ]
        finally:
            conn.close()
    except Exception:
        return []

