# ─── Registry ─────────────────────────────────────────────────────────────────
UNIVERSES: dict[str, list[dict]] = {
    "NIFTY50":  NIFTY50_STOCKS,
    "NIFTY500": NIFTY500_STOCKS,
}


def get_stocks(universe: str = "NIFTY50") -> list[dict]:
    """Return all stock dicts for the given universe, including any custom tickers."""
    base = UNIVERSES.get(universe, NIFTY50_STOCKS)
    custom = _get_custom_stocks_from_db()
    if not custom:
        return base
    # Avoid duplicates: existing symbols in base take priority
    existing_syms = {s["symbol"] for s in base}
    extras = [c for c in custom if c["symbol"] not in existing_syms]
    return base + extras


def get_symbols(universe: str = "NIFTY50") -> list[str]:
    return [s["symbol"] for s in get_stocks(universe)]


def get_sectors(universe: str = "NIFTY50") -> dict[str, list[str]]:
    """Return a mapping of sector name → list of symbols."""
    sectors: dict[str, list[str]] = {}
    for stock in get_stocks(universe):
        sectors.setdefault(stock["sector"], []).append(stock["symbol"])
    return sectors


def get_symbol_to_name(universe: str = "NIFTY50") -> dict[str, str]:
    return {s["symbol"]: s["name"] for s in get_stocks(universe)}


def get_symbol_to_sector(universe: str = "NIFTY50") -> dict[str, str]:
    return {s["symbol"]: s["sector"] for s in get_stocks(universe)}
